    /// Gets the largest possible <see cref="DataSize"/> value.
    /// </summary>
    public static readonly DataSize MaxValue = FromBits(long.MaxValue);

    /// <summary>
    /// Initializes a new instance of the <see cref="DataSize"/> struct with the specified number of bytes.
    /// </summary>
    /// <param name="byteSize">The size in bytes.</param>
    public DataSize(double byteSize)
    {
        Bytes = byteSize;
    }

    /// <summary>Gets the number of bits.</summary>
    public long Bits => (long)Math.Ceiling(Bytes * BitsInByte);

    /// <summary>Gets the number of bytes.</summary>
    public double Bytes { get; }

    /// <summary>Gets the number of kilobytes.</summary>
    public double Kilobytes => Bytes / BytesInKilobyte;

    /// <summary>Gets the number of megabytes.</summary>
    public double Megabytes => Bytes / BytesInMegabyte;

    /// <summary>Gets the number of gigabytes.</summary>
    public double Gigabytes => Bytes / BytesInGigabyte;

    /// <summary>Gets the number of terabytes.</summary>
    public double Terabytes => Bytes / BytesInTerabyte;

    /// <summary>
    /// Gets the largest whole number value and its corresponding unit symbol.
    /// </summary>
    public string LargestWholeNumberSymbol
    {
        get
        {
            GetLargestWholeNumber(out _, out var symbol);
            return symbol;
        }
    }

    /// <summary>
    /// Gets the value in the largest whole number unit.
    /// </summary>
    public double LargestWholeNumberValue
    {
        get
        {
            GetLargestWholeNumber(out var value, out _);
            return value;
        }
    }

    private void GetLargestWholeNumber(out double value, out string symbol)
    {
        var abs = Math.Abs(Bytes);
        if (abs >= BytesInTerabyte) { value = Terabytes; symbol = TerabyteSymbol; }
        else if (abs >= BytesInGigabyte) { value = Gigabytes; symbol = GigabyteSymbol; }
        else if (abs >= BytesInMegabyte) { value = Megabytes; symbol = MegabyteSymbol; }
        else if (abs >= BytesInKilobyte) { value = Kilobytes; symbol = KilobyteSymbol; }
        else if (abs >= 1) { value = Bytes; symbol = ByteSymbol; }
        else { value = Bits; symbol = BitSymbol; }
