/// <summary>
/// Returns a formatted string representation of this data size.
/// </summary>
/// <param name="format">A standard or custom numeric format string.</param>
/// <param name="provider">An object that supplies culture-specific formatting information.</param>
/// <returns>A formatted string representing this data size.</returns>
public string ToString(string? format, IFormatProvider? formatProvider = null)
{
    formatProvider ??= CultureInfo.CurrentCulture;

    if (string.IsNullOrEmpty(format))
    {
        format = "0.##";
    }

    // If format contains a unit symbol, extract it and format the corresponding value
    if (TryMatchUnit(format, TerabyteSymbol, out var numFmt)) return FormatValue(Terabytes, numFmt, TerabyteSymbol, formatProvider);
    if (TryMatchUnit(format, GigabyteSymbol, out numFmt)) return FormatValue(Gigabytes, numFmt, GigabyteSymbol, formatProvider);
    if (TryMatchUnit(format, MegabyteSymbol, out numFmt)) return FormatValue(Megabytes, numFmt, MegabyteSymbol, formatProvider);
    if (TryMatchUnit(format, KilobyteSymbol, out numFmt)) return FormatValue(Kilobytes, numFmt, KilobyteSymbol, formatProvider);
    if (TryMatchUnit(format, ByteSymbol, out numFmt)) return FormatValue(Bytes, numFmt, ByteSymbol, formatProvider);
    if (TryMatchUnit(format, BitSymbol, out numFmt)) return FormatValue(Bits, numFmt, BitSymbol, formatProvider);

    // Auto-select the best unit
    GetLargestWholeNumber(out var value, out var symbol);
    return string.Create(formatProvider, stackalloc char[64], $"{value.ToString(format, formatProvider)} {symbol}");
}

private static bool TryMatchUnit(string format, string unit, out string numericFormat)
{
    var idx = format.IndexOf(unit, StringComparison.OrdinalIgnoreCase);
    if (idx < 0)
    {
        numericFormat = format;
        return false;
    }

    // Extract numeric format by removing the unit token
    numericFormat = string.Concat(format.AsSpan(0, idx).Trim(), format.AsSpan(idx + unit.Length).Trim());
    if (numericFormat.Length == 0) numericFormat = "0.##";
    return true;
}

private static string FormatValue(double value, string numericFormat, string unit, IFormatProvider provider)
{
    Span<char> buffer = stackalloc char[64];
    if (value.TryFormat(buffer, out var written, numericFormat, provider) && written + unit.Length + 1 <= buffer.Length)
    {
        buffer[written] = ' ';
        unit.AsSpan().CopyTo(buffer[(written + 1)..]);
        return new string(buffer[..(written + 1 + unit.Length)]);
    }
    return $"{value.ToString(numericFormat, provider)} {unit}";
}

