17.     public const string KilobyteSymbol = "KB";
18.     public const string MegabyteSymbol = "MB";
19.     public const string GigabyteSymbol = "GB";
20.     public const string TerabyteSymbol = "TB";
21. 
22.     public const long BitsInByte = 8;
23.     public const long BytesInKilobyte = 1024;
24.     public const long BytesInMegabyte = 1_048_576;
25.     public const long BytesInGigabyte = 1_073_741_824;
26.     public const long BytesInTerabyte = 1_099_511_627_776;
